package com.auction.server.service;

import com.auction.server.manage.UserManage;
import com.auction.server.models.User.User;
import com.auction.server.models.User.UserFactory;
import com.auction.server.exception.AuthenticationException;

import java.util.HashMap;
import java.util.Map;
import java.util.UUID;

/**
 * AuthService - Xử lý logic Authentication (Register, Login, Logout, Session)
 * Không dùng Singleton - có thể tạo nhiều instance
 */
public class AuthService {
    private final UserManage userManage = UserManage.getInstance();

    // Session storage: userId → token
    private final Map<String, String> activeSessions = new HashMap<>();

    private static final String EMAIL_REGEX = "^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+$";
    private static final int PASSWORD_MIN_LENGTH = 8;

    // ========== PUBLIC METHODS ==========

    /**
     *  REGISTER - Đăng ký người dùng mới
     * @param username Username (duy nhất)
     * @param password Mật khẩu
     * @param confirmPassword Xác nhận mật khẩu
     * @param email Email (duy nhất)
     * @param role ADMIN, SELLER, hoặc BIDDER
     * @return User object nếu thành công
     * @throws AuthenticationException nếu validate fail
     */
    public synchronized User register(String username, String password, String confirmPassword, 
                                       String email, String role) throws AuthenticationException {
        // 1. Validate input
        if (username == null || username.trim().isEmpty()) {
            throw new AuthenticationException("Lỗi: Username không được null hoặc rỗng");
        }
        if (password == null || password.isEmpty()) {
            throw new AuthenticationException("Lỗi: Mật khẩu không được null hoặc rỗng");
        }
        if (!password.equals(confirmPassword)) {
            throw new AuthenticationException("Lỗi: Mật khẩu xác nhận không khớp");
        }
        if (!isPasswordValid(password)) {
            throw new AuthenticationException("Lỗi: Mật khẩu phải có ít nhất " + PASSWORD_MIN_LENGTH + " ký tự");
        }
        if (!isEmailFormatValid(email)) {
            throw new AuthenticationException("Lỗi: Email không hợp lệ (phải có dấu @)");
        }
        if (role == null || role.trim().isEmpty()) {
            throw new AuthenticationException("Lỗi: Role không được null hoặc rỗng");
        }

        // 2. Tạo user object theo role
        User newUser;
        try {
            newUser = UserFactory.createUser(username, password, email, role);
        } catch (IllegalArgumentException e) {
            throw new AuthenticationException("Lỗi: " + e.getMessage());
        }

        // 3. Lưu vào UserManage (sẽ check username/email trùng)
        if (!userManage.addUser(newUser)) {
            throw new AuthenticationException("Lỗi: Không thể đăng ký. Username hoặc Email có thể đã tồn tại");
        }

        System.out.println("[AuthService] ✅ Đăng ký thành công: " + username + " (Role: " + role + ")");
        return newUser;
    }

    /**
     *  LOGIN - Đăng nhập
     * @param usernameOrEmail Username hoặc Email
     * @param password Mật khẩu
     * @return User object nếu thành công (Client lưu userId + token từ getToken())
     * @throws AuthenticationException nếu username/password sai
     */
    public synchronized User login(String usernameOrEmail, String password) throws AuthenticationException {
        if (usernameOrEmail == null || usernameOrEmail.isEmpty()) {
            throw new AuthenticationException("Lỗi: Username/Email không được null hoặc rỗng");
        }
        if (password == null || password.isEmpty()) {
            throw new AuthenticationException("Lỗi: Mật khẩu không được null hoặc rỗng");
        }

        // 1. Tìm user theo username hoặc email
        User user = userManage.getUserByUsername(usernameOrEmail);
        if (user == null) {
            user = userManage.getUserByEmail(usernameOrEmail);
        }
        if (user == null) {
            throw new AuthenticationException("Lỗi: Username/Email không tồn tại");
        }

        // 2. Kiểm tra password
        if (!user.checkpassword(password)) {
            throw new AuthenticationException("Lỗi: Mật khẩu sai");
        }

        // 3. Tạo token & lưu session
        String token = generateToken();
        activeSessions.put(user.getId(), token);

        System.out.println("[AuthService] ✅ Đăng nhập thành công: " + user.getUsername());
        System.out.println("[AuthService]  Token: " + token.substring(0, 8) + "...");
        System.out.println("[AuthService]  Tổng user online: " + activeSessions.size());

        return user;
    }

    /**
     *  LOGOUT - Đăng xuất (Xóa session)
     * @param userId ID của user cần đăng xuất
     * @throws AuthenticationException nếu userId không có session
     */
    public synchronized void logout(String userId) throws AuthenticationException {
        if (userId == null || userId.isEmpty()) {
            throw new AuthenticationException("Lỗi: User ID không được null hoặc rỗng");
        }
        if (!activeSessions.containsKey(userId)) {
            throw new AuthenticationException("Lỗi: User không đăng nhập hoặc session đã hết");
        }

        activeSessions.remove(userId);
        System.out.println("[AuthService] ✅ Đăng xuất thành công: " + userId);
        System.out.println("[AuthService]  Tổng user online: " + activeSessions.size());
    }

    /**
     * ✅ VERIFY SESSION - Kiểm tra session còn valid không
     * (Gọi mỗi lần client gửi request)
     * @param userId ID của user
     * @param token Token hiện tại
     * @return true nếu session valid
     * @throws AuthenticationException nếu session không valid
     */
    public boolean isSessionValid(String userId, String token) throws AuthenticationException {
        if (userId == null || userId.isEmpty()) {
            throw new AuthenticationException("Lỗi: User ID không được null hoặc rỗng");
        }
        if (token == null || token.isEmpty()) {
            throw new AuthenticationException("Lỗi: Token không được null hoặc rỗng");
        }

        String liveToken = activeSessions.get(userId);
        if (liveToken == null) {
            throw new AuthenticationException("Lỗi: Session không tồn tại. Vui lòng đăng nhập lại");
        }
        if (!liveToken.equals(token)) {
            throw new AuthenticationException("Lỗi: Token không khớp hoặc hết hạn");
        }

        return true;
    }

    /**
     *  CHANGE PASSWORD - Thay đổi mật khẩu
     * @param userId ID của user
     * @param oldPassword Mật khẩu cũ
     * @param newPassword Mật khẩu mới
     * @return true nếu thành công
     * @throws AuthenticationException nếu không hợp lệ
     */
    public synchronized boolean changePassword(String userId, String oldPassword, 
                                                String newPassword) throws AuthenticationException {
        if (userId == null || userId.isEmpty()) {
            throw new AuthenticationException("Lỗi: User ID không được null hoặc rỗng");
        }

        User user = userManage.getUser(userId);
        if (user == null) {
            throw new AuthenticationException("Lỗi: User không tồn tại");
        }

        // Kiểm tra mật khẩu cũ
        if (!user.checkpassword(oldPassword)) {
            throw new AuthenticationException("Lỗi: Mật khẩu cũ không chính xác");
        }

        // Kiểm tra mật khẩu mới hợp lệ
        if (!isPasswordValid(newPassword)) {
            throw new AuthenticationException("Lỗi: Mật khẩu mới phải có ít nhất " + PASSWORD_MIN_LENGTH + " ký tự");
        }

        System.out.println("[AuthService] ✅ Thay đổi mật khẩu thành công: " + user.getUsername());
        return true;
    }

    /**
     *  GET TOKEN - Lấy token của user (sau khi login thành công)
     * @param userId ID của user
     * @return Token string
     */
    public String getToken(String userId) {
        return activeSessions.get(userId);
    }

    /**
     *  GET ONLINE COUNT - Lấy số user đang online
     * @return Số user hiện tại có session active
     */
    public int getOnlineUserCount() {
        return activeSessions.size();
    }

    // ========== PRIVATE HELPER METHODS ==========

    /**
     * Kiểm tra định dạng email (regex)
     */
    private boolean isEmailFormatValid(String email) {
        if (email == null || email.isEmpty()) {
            return false;
        }
        return email.matches(EMAIL_REGEX);
    }

    /**
     * Kiểm tra mật khẩu hợp lệ (độ dài tối thiểu)
     */
    private boolean isPasswordValid(String password) {
        return password != null && password.length() >= PASSWORD_MIN_LENGTH;
    }

    /**
     * Tạo token random (UUID)
     * Ví dụ: "e7c1a88f-82d5-4a1e-8fae-1c2b3d4e5f6g"
     */
    private String generateToken() {
        return UUID.randomUUID().toString();
    }
}
